INSERT INTO `sanpham` (`MaSP`, `TenSP`, `MoTa`, `Status`, `MaLoai`, `CreatedAt`, `UpdatedAt`) VALUES
(1, 'Giày Nike Air Force 1 07 Triple White CW2288-111', 'Nike Air Force 1 ’07 Triple White là biểu tượng của phong cách đơn giản nhưng tinh tế, mang tới cảm giác cổ điển đậm chất streetwear nhưng vẫn dễ phối đồ trong mọi tình huống.', 1, 1, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(2, 'Giày Thể Thao Nữ MWC A197- Giày Thể Thao Nữ Dáng Sneaker Đi Học, Đi Chơi, Giày Thể Thao Nữ Siêu Bền Đẹp, Thời Trang', 'Giày Thể Thao Nữ MWC A197 là lựa chọn lý tưởng dành cho các bạn nữ yêu thích phong cách năng động – trẻ trung – tiện dụng, phù hợp mang hàng ngày từ đi học, đi làm đến đi chơi, dạo phố. Với thiết kế sneaker hiện đại kết hợp sự thoải mái tối đa, MWC A197 không chỉ là một đôi giày mà còn là điểm nhấn thời trang cho mọi outfit.', 1, 1, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(3, 'Giày thể thao sneaker nam nữ màu đen, giày chạy bộ, giày học sinh', 'Giày thể thao sneaker nam nữ màu đen là lựa chọn hoàn hảo cho những ai yêu thích phong cách đơn giản – năng động – tiện dụng, phù hợp cho nhiều mục đích sử dụng như đi học, đi làm, chạy bộ nhẹ, tập thể dục hay đi chơi hằng ngày. Với gam màu đen basic, đôi giày mang lại vẻ ngoài gọn gàng, sạch sẽ và rất dễ phối đồ.', 1, 1, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(4, 'Giày nam đa năng đế mềm, giày trắng thoáng khí, giày thể thao ngoài trời, giày sneaker phong cách nam', 'Chất liệu cao su đúc, chống nước tốt', 1, 1, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(5, 'Giày Nam MenShoes G236, Giày Thể Thao Nam Sneaker Mẫu Hot,Vải Thoáng Khí Chất Liệu Đế Cao Su Mềm Chống Trơn Trượt', 'Giày Nam MenShoes G236 là mẫu sneaker thể thao nam đang được ưa chuộng nhờ thiết kế hiện đại, trẻ trung cùng khả năng mang êm và bền bỉ. Đôi giày phù hợp cho nam giới yêu thích phong cách năng động – gọn gàng – tiện dụng, đáp ứng tốt nhu cầu đi học, đi làm, đi chơi hay vận động hằng ngày.', 1, 1, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(6, 'Giày Nam, Giày Sneaker Nam Cổ Thấp Phong Cách Hàn Quốc - K22', 'Giày Sneaker Nam K22 là mẫu giày cổ thấp mang đậm phong cách Hàn Quốc trẻ trung, tối giản nhưng đầy tinh tế, phù hợp cho nam giới yêu thích sự gọn gàng, thời trang và tiện dụng trong sinh hoạt hằng ngày. Đây là lựa chọn lý tưởng cho đi học, đi làm, đi chơi hay dạo phố.', 1, 1, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(7, 'Giày lười nam trung niên chất liệu da bò cao cấp, giày tặng cha', 'Giày lười nam trung niên da bò cao cấp là lựa chọn hoàn hảo dành cho các quý ông yêu thích sự đơn giản – lịch sự – thoải mái. Với thiết kế tinh tế cùng chất liệu da bò thật bền đẹp, đôi giày không chỉ mang lại cảm giác êm ái khi sử dụng mà còn thể hiện sự quan tâm, trân trọng khi dùng làm quà tặng cho cha, chú, bác hoặc người thân lớn tuổi.', 1, 1, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(8, 'Giày Blazer Low 77 Jumbo Year of The Snake 3 màu hot 2025', 'Nike Blazer Low ’77 Jumbo – Year of The Snake là phiên bản đặc biệt lấy cảm hứng từ năm Tỵ, kết hợp giữa thiết kế Blazer cổ điển và phong cách Jumbo hiện đại, cá tính. Mẫu giày mang đậm dấu ấn thời trang 2025, phù hợp cho cả nam và nữ yêu thích sneaker độc đáo, khác biệt nhưng vẫn dễ phối đồ.', 1, 1, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(9, 'Giày Onitsuka_tiger tokuten các màu nam nữ, giày Onitsuka bản cao cấp full boxx hot trend', 'Onitsuka Tiger Tokuten là dòng sneaker mang đậm tinh thần retro – thể thao – thời trang Nhật Bản, đang cực kỳ được ưa chuộng trong giới trẻ. Với thiết kế gọn gàng, dễ mang cùng nhiều màu sắc thời thượng, Tokuten phù hợp cho cả nam và nữ, đi học, đi chơi hay phối outfit streetwear đều rất nổi bật.', 1, 1, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(10, 'Giày G.V.C giày Băng Đai Chéo. Đen, Xám bản quai chun độc đáo - giầy lười nam Hoot trend 2024', 'Giày G.V.C băng đai chéo là mẫu giày lười nam nổi bật với thiết kế quai chun đan chéo độc đáo, mang lại cảm giác mới lạ, cá tính nhưng vẫn cực kỳ tiện dụng. Phù hợp cho nam giới yêu thích phong cách năng động – gọn gàng – dễ mang, dùng hằng ngày từ đi làm, đi chơi đến dạo phố.', 1, 1, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(11, 'Giày thể thao Vans_ 𝗞𝗻𝘂 𝗦𝗸𝗼𝗼𝗹 & 𝗜𝗺𝗿𝗮𝗻 𝗣𝗼𝘁𝗮𝘁𝗼 mẫu mới hàng Full Box', 'Vans Knu Skool & Imran Potato là những mẫu sneaker mới nổi bật trong làng streetwear, mang đậm tinh thần Y2K – retro – cá tính, đang được giới trẻ săn đón mạnh mẽ. Với thiết kế form to bản đặc trưng cùng các chi tiết độc đáo, đây là lựa chọn hoàn hảo cho những ai yêu thích phong cách bụi bặm, nổi bật và khác biệt.', 1, 1, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(12, 'Giày MLB, Giày Boston, NY, LA \"FreeShip\" mới nhất hót nhất 2023 bản chuẩn.', 'iày MLB Boston – New York (NY) – Los Angeles (LA) là dòng sneaker thời trang đình đám, nổi bật với thiết kế chunky cá tính, logo đội bóng biểu tượng và phong cách streetwear hiện đại. Đây là lựa chọn được giới trẻ săn đón mạnh mẽ nhờ khả năng phối đồ dễ – mang êm – form đẹp, phù hợp cho cả nam và nữ.', 1, 1, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(13, 'Dép Bánh Mì Yz Slide Bản Vân nhám và - Đế Cao Chất Lượng', 'Dép bánh mì YZ Slide bản vân nhám là mẫu dép thời trang tối giản nhưng cực kỳ nổi bật, lấy cảm hứng từ phong cách streetwear hiện đại. Với thiết kế đế cao bản dày cùng bề mặt vân nhám cá tính, đôi dép mang lại cảm giác êm – nhẹ – thời thượng, phù hợp cho cả nam và nữ sử dụng hằng ngày.', 1, 2, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(14, 'Giày Conve_Chuck Taylor 1970s,Giày Thể Thao Conve Phong Cách Thời Trang Dành Cho Nam Và Nữ Full Box.', 'Converse Chuck Taylor 1970s (Chuck 70s) là dòng sneaker kinh điển được nâng cấp từ mẫu Chuck Taylor huyền thoại, mang đậm phong cách retro – thời trang – cá tính, phù hợp cho cả nam và nữ. Đây là mẫu giày luôn giữ vững sức hút qua nhiều năm và chưa bao giờ lỗi mốt.', 1, 1, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(15, 'Giày SB 58 Nam Nữ – 2 Màu Hot  Sneaker Bản Cao Cấp – Full Bill, Box Đầy Đủ', 'Giày SB 58 là mẫu sneaker mang phong cách trẻ trung – năng động – dễ phối đồ, phù hợp cho cả nam và nữ. Với thiết kế gọn gàng, 2 phối màu basic thời thượng cùng form chuẩn dễ mang, SB 58 là lựa chọn lý tưởng cho đi học, đi chơi, dạo phố hằng ngày.', 1, 1, '2025-12-31 17:40:24', '2026-01-01 12:06:46'),
(16, 'Giày SB 58  sneaker', 'Giày SB 58 là mẫu sneaker mang phong cách trẻ trung – năng động – dễ phối đồ, phù hợp cho cả nam và nữ. Với thiết kế gọn gàng, 2 phối màu basic thời thượng cùng form chuẩn dễ mang, SB 58 là lựa chọn lý tưởng cho đi học, đi chơi, dạo phố hằng ngày.', 0, 1, '2025-12-31 17:40:24', '2026-01-03 20:54:23'),
(17, 'Giày Adidas Samba OG Đủ Các Màu Cho Nam Và Nữ,Giày Sneaker Bản Cao Cấp Full Bill Box', 'Adidas Samba OG là mẫu sneaker kinh điển vượt thời gian, luôn nằm trong top giày bán chạy nhờ thiết kế retro thể thao pha streetwear hiện đại. Với form dáng gọn gàng, dễ mang và bảng màu đa dạng, Samba OG phù hợp cho cả nam và nữ, đi học, đi chơi hay phối outfit hằng ngày đều rất đẹp.', 1, 1, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(18, 'Dép siêu sao một mảnh chống nước cao 4cm, Unisex Hottrend 2025 D7737', 'Dép Siêu Sao D7737 là mẫu dép đúc nguyên khối (một mảnh) đang cực kỳ được ưa chuộng nhờ thiết kế tối giản, bền bỉ và khả năng chống nước vượt trội. Đế cao 4cm giúp tôn dáng nhẹ nhàng, phù hợp cho cả nam và nữ sử dụng hằng ngày theo phong cách năng động, hiện đại.', 1, 2, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(19, 'Dép Quai Ngang Nam Nữ, Dép Nam Đẹp Sport , Giày Dép Đi Trong Nhà, Văn Phòng Mẫu Đẹp DP10', 'Dép quai ngang nam nữ DP10 mang phong cách thể thao đơn giản, phù hợp cho cả nam và nữ, dễ dàng sử dụng trong nhiều hoàn cảnh như đi trong nhà, đi văn phòng hoặc ra ngoài hằng ngày. Dép có thiết kế đẹp, form gọn gàng, dễ phối đồ, đế dép êm nhẹ giúp mang lâu không đau chân, tạo cảm giác thoải mái khi di chuyển. Sản phẩm phù hợp với nhiều độ tuổi, là lựa chọn tiện lợi cho sinh hoạt hằng ngày.', 1, 2, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(20, 'Dép Nam L.V Quai Ngang - Dép Nam GC Mẫu Mới Hàng Full Cao Su Đế Dép Có LoGo Xịn Xò', 'Dép nam L.V quai ngang – dép nam GC mẫu mới được thiết kế theo phong cách thời trang hiện đại, nam tính, phù hợp đi chơi, đi dạo hoặc sử dụng hằng ngày. Dép làm từ cao su nguyên khối cao cấp, đế dày dặn, êm chân, hạn chế trơn trượt khi di chuyển. Phần quai ngang chắc chắn, ôm chân tốt, nổi bật với logo xịn xò tạo điểm nhấn sang trọng và đẳng cấp. Sản phẩm vừa bền đẹp vừa tiện lợi, dễ phối đồ, phù hợp cho nhiều độ tuổi nam giới.', 1, 2, '2025-12-31 17:40:24', '2025-12-31 17:40:24'),
(21, 'Dép Doctor LUXURY Cao Cấp Da Xuất Nhập, Bản Đế Vừa Lót Mút Êm Chân, Đế Cao Su Đúc Khâu Chỉ.', 'Dép Doctor LUXURY cao cấp da xuất nhập sở hữu thiết kế sang trọng, lịch lãm, phù hợp cho nam giới sử dụng hằng ngày hoặc làm quà tặng. Dép được làm từ chất liệu da cao cấp, mềm mại, bền đẹp theo thời gian. Phần lót mút êm chân giúp giảm mỏi khi đi lâu, tạo cảm giác thoải mái tối đa. Đế cao su đúc chắc chắn, khâu chỉ tỉ mỉ tăng độ bền và chống trơn trượt hiệu quả. Sản phẩm mang phong cách cao cấp, tinh tế, phù hợp nhiều độ tuổi và hoàn cảnh sử dụng.', 1, 2, '2025-12-31 17:40:24', '2025-12-31 17:40:24');
